import { useForm, FormProvider } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import { z } from 'zod';
import { useState } from 'react';

// Schémas par étape
const etape1Schema = z.object({
  nom: z.string().min(3),
  email: z.string().email(),
  telephone: z.string().regex(/^[67][0-9]{7}$/)
});

const etape2Schema = z.object({
  produits: z.array(z.object({
    id: z.string(),
    nom: z.string(),
    quantite: z.number().min(1),
    options: z.object({ taille: z.string().optional(), couleur: z.string().optional() }).optional()
  })).min(1, 'Sélectionnez au moins un produit')
});

const etape3Schema = z.object({
  adresse: z.string().min(5),
  ville: z.enum(['Douala', 'Yaoundé', 'Garoua', 'Bafoussam', 'Bamenda']),
  modePaiement: z.enum(['mtn', 'orange', 'carte', 'livraison'])
});

const formulaireCompletSchema = etape1Schema.merge(etape2Schema).merge(etape3Schema);

function CommandeMultiEtape() {
  const [etape, setEtape] = useState(1);
  const methods = useForm({
    resolver: zodResolver(formulaireCompletSchema),
    defaultValues: {
      produits: [],
      ville: 'Douala',
      modePaiement: 'mtn'
    }
  });

  const { trigger, getValues, handleSubmit, formState: { errors } } = methods;

  const validerEtape = async (etapeCourante) => {
    let champsAValider = [];
    if (etapeCourante === 1) champsAValider = ['nom', 'email', 'telephone'];
    if (etapeCourante === 2) champsAValider = ['produits'];
    if (etapeCourante === 3) champsAValider = ['adresse', 'ville', 'modePaiement'];

    const isValid = await trigger(champsAValider);
    if (isValid) setEtape(etapeCourante + 1);
  };

  const onSubmit = (data) => {
    alert(`Commande validée !\n${JSON.stringify(data, null, 2)}`);
  };

  return (
    &lt;FormProvider {...methods}&gt;
      &lt;form onSubmit={handleSubmit(onSubmit)}&gt;
        {etape === 1 && (
          &lt;div&gt;
            &lt;h3&gt;Étape 1 : Identité&lt;/h3&gt;
            &lt;input {...methods.register('nom')} placeholder="Nom" /&gt;
            &lt;input {...methods.register('email')} placeholder="Email" /&gt;
            &lt;input {...methods.register('telephone')} placeholder="Téléphone" /&gt;
            &lt;button type="button" onClick={() => validerEtape(1)}&gt;Suivant&lt;/button&gt;
          &lt;/div&gt;
        )}

        {etape === 2 && (
          &lt;div&gt;
            &lt;h3&gt;Étape 2 : Produits&lt;/h3&gt;
            &lt;button type="button" onClick={() => setEtape(1)}&gt;Précédent&lt;/button&gt;
            &lt;button type="button" onClick={() => validerEtape(2)}&gt;Suivant&lt;/button&gt;
          &lt;/div&gt;
        )}

        {etape === 3 && (
          &lt;div&gt;
            &lt;h3&gt;Étape 3 : Livraison&lt;/h3&gt;
            &lt;textarea {...methods.register('adresse')} placeholder="Adresse" /&gt;
            &lt;select {...methods.register('ville')}&gt;
              &lt;option&gt;Douala&lt;/option&gt;&lt;option&gt;Yaoundé&lt;/option&gt;
            &lt;/select&gt;
            &lt;select {...methods.register('modePaiement')}&gt;
              &lt;option value="mtn"&gt;MTN Mobile Money&lt;/option&gt;
              &lt;option value="orange"&gt;Orange Money&lt;/option&gt;
            &lt;/select&gt;
            &lt;button type="button" onClick={() => setEtape(2)}&gt;Précédent&lt;/button&gt;
            &lt;button type="submit"&gt;Valider la commande&lt;/button&gt;
          &lt;/div&gt;
        )}

        &lt;div&gt;
          &lt;pre&gt;{JSON.stringify(getValues(), null, 2)}&lt;/pre&gt;
        &lt;/div&gt;
      &lt;/form&gt;
    &lt;/FormProvider&gt;
  );
}
