import { useForm } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import { z } from 'zod';
import { useState, useEffect } from 'react';

const feedbackSchema = z.object({
  nom: z.string().min(2),
  email: z.string().email(),
  message: z.string().min(10).max(500),
  note: z.number().min(1).max(5),
  motDePasse: z.string().min(6)
});

function FeedbackForm() {
  const [forceMotDePasse, setForceMotDePasse] = useState(0);
  const { register, watch, formState: { errors, isValid }, trigger } = useForm({
    resolver: zodResolver(feedbackSchema),
    mode: 'onChange' // Revalide à chaque changement
  });

  const motDePasse = watch('motDePasse', '');

  useEffect(() => {
    // Calcul de la force du mot de passe (0-100)
    let force = 0;
    if (motDePasse.length >= 6) force += 25;
    if (/[A-Z]/.test(motDePasse)) force += 25;
    if (/[0-9]/.test(motDePasse)) force += 25;
    if (/[^A-Za-z0-9]/.test(motDePasse)) force += 25;
    setForceMotDePasse(force);
  }, [motDePasse]);

  // Validation debounce sur le message
  const handleMessageChange = (e) => {
    const value = e.target.value;
    clearTimeout(window.messageTimeout);
    window.messageTimeout = setTimeout(() => {
      trigger('message');
    }, 500);
  };

  const onSubmit = (data) => {
    alert(`Merci ${data.nom} pour votre retour !`);
  };

  return (
    &lt;form onSubmit={handleSubmit(onSubmit)}&gt;
      &lt;div&gt;
        &lt;input {...register('nom')} placeholder="Nom" /&gt;
        {errors.nom && &lt;span&gt;{errors.nom.message}&lt;/span&gt;}
      &lt;/div&gt;

      &lt;div&gt;
        &lt;input {...register('email')} placeholder="Email" /&gt;
        {errors.email && &lt;span&gt;{errors.email.message}&lt;/span&gt;}
      &lt;/div&gt;

      &lt;div&gt;
        &lt;input {...register('motDePasse')} type="password" placeholder="Mot de passe" /&gt;
        &lt;progress value={forceMotDePasse} max="100" /&gt;
        &lt;span&gt;Force : {forceMotDePasse}%&lt;/span&gt;
      &lt;/div&gt;

      &lt;div&gt;
        &lt;select {...register('note', { valueAsNumber: true })}&gt;
          {[1,2,3,4,5].map(n => &lt;option key={n} value={n}&gt;{n} étoile{n&gt;1?'s':''}&lt;/option&gt;)}
        &lt;/select&gt;
      &lt;/div&gt;

      &lt;div&gt;
        &lt;textarea {...register('message')} onChange={handleMessageChange} placeholder="Votre message..." /&gt;
        {errors.message && &lt;span&gt;{errors.message.message}&lt;/span&gt;}
      &lt;/div&gt;

      &lt;button type="submit" disabled={!isValid}&gt;Envoyer&lt;/button&gt;
    &lt;/form&gt;
  );
}
